mapper.select:
SELECT count(*)
FROM cong_doan
WHERE ma_du_an = #{maDuAn}

SELECT *
FROM cong_doan
WHERE stt_cong_doan = #{sttCongDoan}
AND ma_du_an = #{maDuAn}

mapper.delete:
DELETE FROM cong_doan
WHERE stt_cong_doan = #{sttCongDoan}
AND ma_du_an = #{maDuAn}

mapper.select:
SELECT DISTINCT tgd.ma_nhan_vien AS maNv, nv.ho_ten AS hoTen, tgd.vai_tro AS vaiTro, tgd.thang AS thang, tgd.nam AS nam FROM tham_gia_du_an tgd JOIN nhan_vien nv ON nv.ma_nhan_vien = tgd.ma_nhan_vien JOIN cong_doan cd ON cd.ma_du_an = tgd.ma_du_an WHERE cd.ma_du_an = #{maDuAn} AND cd.stt_cong_doan = #{sttCongDoan}
-- GIAO THÁNG THAM GIA VỚI THỜI GIAN CÔNG ĐOẠN AND LAST_DAY( STR_TO_DATE(CONCAT(tgd.nam,'-',tgd.thang,'-01'),'%Y-%m-%d') ) >= cd.ngay_bat_dau AND STR_TO_DATE( CONCAT(tgd.nam,'-',tgd.thang,'-01'),'%Y-%m-%d' ) <= cd.ngay_hoan_thanh_du_kien
-- KHÔNG LẤY NHÂN VIÊN ĐÃ THỰC HIỆN CÔNG ĐOẠN AND NOT EXISTS ( SELECT 1 FROM thuc_hien_cong_doan thcd WHERE thcd.ma_du_an = cd.ma_du_an AND thcd.stt_cong_doan = cd.stt_cong_doan AND thcd.ma_nhan_vien = tgd.ma_nhan_vien )
